import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Input from "../components/Input";
import Button from "../components/Button";
import IconMessage from "../components/IconMessage";

const Chat = () => {
  return (
    <div className="h-screen flex overflow-hidden">
      <div className={`w-[30%] flex flex-col ${darkMode ? "bg-[#0a0f27] text-white" : "bg-[#dde3f6]"}`}>
        <Button onClick={() => setDarkMode(!darkMode)}>Toggle Dark Mode</Button>
        <Button onClick={() => navigate("/")}>Go Home</Button>
      </div>
      <div className={`w-[70%] h-full overflow-scroll scrollbar-hide ${darkMode ? "bg-[#0a0f27] bg-opacity-90 text-white" : "bg-white"}`}>
        <div className="p-4">
          {error && <p className="text-red-500">{error}</p>}
          <Input placeholder="Type your message..." value={message} onChange={(e) => setMessage(e.target.value)} />
          <Button onClick={handleChat}>Send</Button>
          <div>
            <h2>Response:</h2>
            <p>{chatResponse}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Chat;
